import { createSlice, createAsyncThunk } from '@reduxjs/toolkit';
import { cartAPI } from '../../services/api';

// ============================================================================
// SAFETY HELPERS: Prevents the app from crashing on bad local storage data
// ============================================================================
const loadCartFromStorage = () => {
  try {
    const savedCart = localStorage.getItem('cart');
    return savedCart ? JSON.parse(savedCart) : [];
  } catch (error) {
    console.error("Corrupted cart data in localStorage. Resetting.", error);
    return [];
  }
};

const saveCartToStorage = (items) => {
  try {
    localStorage.setItem('cart', JSON.stringify(items));
  } catch (error) {
    console.error("Failed to save cart to localStorage.", error);
  }
};

// ============================================================================
// ASYNC THUNKS
// ============================================================================
export const syncCart = createAsyncThunk(
  'cart/sync',
  async (_, { getState, rejectWithValue }) => {
    try {
      const { cart } = getState();
      const response = await cartAPI.sync(cart.items);
      return response.data;
    } catch (error) {
      return rejectWithValue(error.response?.data);
    }
  }
);

// ============================================================================
// SLICE
// ============================================================================
const cartSlice = createSlice({
  name: 'cart',
  initialState: {
    items: loadCartFromStorage(),
    reservationIds: {},
    loading: false,
  },
  reducers: {
    addToCart: (state, action) => {
      // Extract properties safely
      let product = action.payload?.product;
      let variant = action.payload?.variant;
      let quantity = action.payload?.quantity || 1;

      // DEFENSIVE CHECK: Automatically normalize flat payloads to prevent crashes
      if (!product && action.payload) {
        product = action.payload;
        variant = action.payload.variants?.[0] || {
          variant_id: action.payload.variantId || `var_${action.payload._id || 'default'}`,
          price: action.payload.price || 0
        };
      }

      // Final fallback to prevent any undefined object reads
      if (!variant) {
        variant = { variant_id: 'default', price: product?.price || 0 };
      }

      const existing = state.items.find(
        (item) =>
          item.productId === product._id &&
          item.variantId === variant.variant_id
      );

      if (existing) {
        existing.quantity += quantity;
      } else {
        state.items.push({
          productId: product._id,
          variantId: variant.variant_id,
          name: product.name,
          image: product.images?.[0]?.url || product.image || product.imageUrl,
          price: variant.price || product.price,
          quantity,
          slug: product.slug,
        });
      }
      saveCartToStorage(state.items);
    },

    removeFromCart: (state, action) => {
      const { productId, variantId } = action.payload || {};
      if (!productId) return;

      state.items = state.items.filter(
        (item) =>
          !(item.productId === productId && item.variantId === variantId)
      );
      saveCartToStorage(state.items);
    },

    updateQuantity: (state, action) => {
      const { productId, variantId, quantity } = action.payload || {};
      const item = state.items.find(
        (i) => i.productId === productId && i.variantId === variantId
      );
      if (item) {
        item.quantity = Math.max(1, quantity);
        saveCartToStorage(state.items);
      }
    },

    setReservation: (state, action) => {
      const { productId, variantId, reservationId } = action.payload || {};
      if (productId && variantId) {
        state.reservationIds[`${productId}_${variantId}`] = reservationId;
      }
    },

    clearCart: (state) => {
      state.items = [];
      state.reservationIds = {};
      try {
        localStorage.removeItem('cart');
      } catch (error) {
        console.error("Failed to clear localStorage", error);
      }
    },
  },
});

export const {
  addToCart,
  removeFromCart,
  updateQuantity,
  setReservation,
  clearCart,
} = cartSlice.actions;

export default cartSlice.reducer;
